'use client'
import { cn } from '@cascivo/core'
import type { ReactNode } from 'react'
import styles from './auth-layout.module.css'

export interface AuthLayoutProps {
  children: ReactNode
  logo?: ReactNode
  className?: string
}

export function AuthLayout({ children, logo, className }: AuthLayoutProps) {
  return (
    <div className={cn(styles['layout'], className)}>
      <div className={styles['card']}>
        {logo && <div className={styles['logo']}>{logo}</div>}
        {children}
      </div>
    </div>
  )
}

@layer cascivo.component {
  .layout {
    display: grid;
    place-items: center;
    min-block-size: 100dvh;
    background: var(--cascivo-color-bg-subtle, var(--cascivo-color-surface));
    padding: var(--cascivo-space-4);
  }

  .card {
    inline-size: 100%;
    max-inline-size: 24rem;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    padding: var(--cascivo-space-8);
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-6);
  }

  .logo {
    display: flex;
    justify-content: center;
  }
}
